class ConditionalI18nExtension(Extension):
    """Adds a ``ctrans`` tag that conditionally renders a translation.

    ::

        {% ctrans condition %}Hello{% fallback %}Hi{% endctrans %}

    The ``condition`` is evaluated at render time.  If it is truthy the
    block behaves like a normal ``trans`` block (translated through
    ``gettext``/``ngettext``).  If it is falsy the mandatory ``fallback``
    block is rendered instead, with the same variable substitution rules.
    """

    tags = {"ctrans"}

    def parse(self, parser: "Parser") -> t.Union[nodes.Node, t.List[nodes.Node]]:
        """Parse a conditional translatable tag."""
        lineno = next(parser.stream).lineno
        num_called_num = False

        condition = parser.parse_expression()

        plural_expr: t.Optional[nodes.Expr] = None
        plural_expr_assignment: t.Optional[nodes.Assign] = None
        variables: t.Dict[str, nodes.Expr] = {}
        trimmed = None
        while parser.stream.current.type != "block_end":
            if variables:
                parser.stream.expect("comma")

            # skip colon for python compatibility
            if parser.stream.skip_if("colon"):
                break

            token = parser.stream.expect("name")
            if token.value in variables:
                parser.fail(
                    f"translatable variable {token.value!r} defined twice.",
                    token.lineno,
                    exc=TemplateAssertionError,
                )

            # expressions
            if parser.stream.current.type == "assign":
                next(parser.stream)
                variables[token.value] = var = parser.parse_expression()
            elif trimmed is None and token.value in ("trimmed", "notrimmed"):
                trimmed = token.value == "trimmed"
                continue
            else:
                variables[token.value] = var = nodes.Name(token.value, "load")

            if plural_expr is None:
                if isinstance(var, nodes.Call):
                    plural_expr = nodes.Name("_trans", "load")
                    variables[token.value] = plural_expr
                    plural_expr_assignment = nodes.Assign(
                        nodes.Name("_trans", "store"), var
                    )
                else:
                    plural_expr = var
                num_called_num = token.value == "num"

        parser.stream.expect("block_end")

        plural: t.Optional[str] = None
        have_plural = False
        referenced: t.Set[str] = set()

        # parse the translatable content, stopping at pluralize, fallback,
        # or (if fallback is missing) endctrans.
        singular_names, singular, end_tag = self._parse_block(
            parser, ("pluralize", "fallback", "endctrans")
        )
        if singular_names:
            referenced.update(singular_names)
            if plural_expr is None:
                plural_expr = nodes.Name(singular_names[0], "load")
                num_called_num = singular_names[0] == "num"

        # if we have a pluralize block, we parse that too
        if end_tag == "pluralize":
            have_plural = True
            next(parser.stream)
            if parser.stream.current.type != "block_end":
                token = parser.stream.expect("name")
                if token.value not in variables:
                    parser.fail(
                        f"unknown variable {token.value!r} for pluralization",
                        token.lineno,
                        exc=TemplateAssertionError,
                    )
                plural_expr = variables[token.value]
                num_called_num = token.value == "num"
            parser.stream.expect("block_end")
            plural_names, plural, end_tag = self._parse_block(
                parser, ("fallback", "endctrans")
            )
            referenced.update(plural_names)

        if end_tag != "fallback":
            parser.fail(
                "expected 'fallback' block in conditional translation tag", lineno
            )

        next(parser.stream)  # consume the 'fallback' name token
        parser.stream.expect("block_end")
        fallback_names, fallback, end_tag = self._parse_block(parser, ("endctrans",))
        referenced.update(fallback_names)
        next(parser.stream)  # consume the 'endctrans' name token

        # register free names as simple name expressions
        for name in referenced:
            if name not in variables:
                variables[name] = nodes.Name(name, "load")

        if not have_plural:
            plural_expr = None
        elif plural_expr is None:
            parser.fail("pluralize without variables", lineno)

        if trimmed is None:
            trimmed = self.environment.policies["ext.i18n.trimmed"]
        if trimmed:
            singular = self._trim_whitespace(singular)
            if plural:
                plural = self._trim_whitespace(plural)
            fallback = self._trim_whitespace(fallback)

        node = self._make_conditional_node(
            condition,
            singular,
            plural,
            fallback,
            variables,
            plural_expr,
            bool(referenced),
            num_called_num and have_plural,
        )
        node.set_lineno(lineno)
        if plural_expr_assignment is not None:
            return [plural_expr_assignment, node]
        else:
            return node

    def _trim_whitespace(self, string: str, _ws_re: t.Pattern[str] = _ws_re) -> str:
        return _ws_re.sub(" ", string.strip())

    def _parse_block(
        self, parser: "Parser", end_names: t.Sequence[str]
    ) -> t.Tuple[t.List[str], str, str]:
        """Parse until one of the block tags named in ``end_names`` is
        found.  Returns the referenced variable names, the parsed text
        (with ``%(name)s`` placeholders for variables), and the name of
        the block tag that ended parsing.
        """
        referenced = []
        buf = []

        while True:
            if parser.stream.current.type == "data":
                buf.append(parser.stream.current.value.replace("%", "%%"))
                next(parser.stream)
            elif parser.stream.current.type == "variable_begin":
                next(parser.stream)
                name = parser.stream.expect("name").value
                referenced.append(name)
                buf.append(f"%({name})s")
                parser.stream.expect("variable_end")
            elif parser.stream.current.type == "block_begin":
                next(parser.stream)
                for end_name in end_names:
                    if parser.stream.current.test(f"name:{end_name}"):
                        return referenced, concat(buf), end_name
                parser.fail(
                    "control structures in translatable sections are not allowed"
                )
            elif parser.stream.eos:
                parser.fail("unclosed conditional translation block")
            else:
                raise RuntimeError("internal parser error")

    def _make_conditional_node(
        self,
        condition: nodes.Expr,
        singular: str,
        plural: t.Optional[str],
        fallback: str,
        variables: t.Dict[str, nodes.Expr],
        plural_expr: t.Optional[nodes.Expr],
        vars_referenced: bool,
        num_called_num: bool,
    ) -> nodes.If:
        """Generates an ``If`` node that renders the translation when
        ``condition`` is true and the fallback content otherwise.
        """
        newstyle = self.environment.newstyle_gettext  # type: ignore
        node: nodes.Expr

        # no variables referenced?  no need to escape for old style
        # gettext invocations only if there are vars.
        if not vars_referenced and not newstyle:
            singular = singular.replace("%%", "%")
            if plural:
                plural = plural.replace("%%", "%")

        # singular only:
        if plural_expr is None:
            gettext = nodes.Name("gettext", "load")
            node = nodes.Call(gettext, [nodes.Const(singular)], [], None, None)

        # singular and plural
        else:
            ngettext = nodes.Name("ngettext", "load")
            node = nodes.Call(
                ngettext,
                [nodes.Const(singular), nodes.Const(plural), plural_expr],
                [],
                None,
                None,
            )

        # in case newstyle gettext is used, the method is powerful
        # enough to handle the variable expansion and autoescape
        # handling itself
        if newstyle:
            for key, value in variables.items():
                # the function adds that later anyways in case num was
                # called num, so just skip it.
                if num_called_num and key == "num":
                    continue
                node.kwargs.append(nodes.Keyword(key, value))

        # otherwise do that here
        else:
            # mark the return value as safe if we are in an
            # environment with autoescaping turned on
            node = nodes.MarkSafeIfAutoescape(node)
            if variables:
                node = nodes.Mod(
                    node,
                    nodes.Dict(
                        [
                            nodes.Pair(nodes.Const(key), value)
                            for key, value in variables.items()
                        ]
                    ),
                )
        translation_stmt = nodes.Output([node])

        # the fallback content is plain text, never routed through
        # gettext/ngettext, but it still supports the same %(name)s
        # variable substitution as the translated branch.
        fallback_node: nodes.Expr = nodes.Const(
            fallback if variables else fallback.replace("%%", "%")
        )
        fallback_node = nodes.MarkSafeIfAutoescape(fallback_node)
        if variables:
            fallback_node = nodes.Mod(
                fallback_node,
                nodes.Dict(
                    [
                        nodes.Pair(nodes.Const(key), value)
                        for key, value in variables.items()
                    ]
                ),
            )
        fallback_stmt = nodes.Output([fallback_node])

        return nodes.If(condition, [translation_stmt], [], [fallback_stmt])


